(function ($) {
    $.fn.imageUploader = function (options) {
        let defaults = {
            preloaded: [],
            imagesInputName: "images ",
            preloadedInputName: "preloaded",
            label: "Drag & Drop files here / Click to browse"
        };
        let plugin = this;
        plugin.settings = {};
        plugin.init = function () {
            plugin.settings = $.extend(plugin.settings, defaults, options);
            plugin.each(function (i, wrapper) {
                let $container = createContainer();
                $(wrapper).append($container);
                $container.on("dragover", fileDragHover.bind($container));
                $container.on("dragleave", fileDragHover.bind($container));
                $container.on("drop", fileSelectHandler.bind($container));
                if (plugin.settings.preloaded.length) {
                    $container.addClass("has-files");
                    let $uploadedContainer = $container.find(".uploaded");
                    for (let i = 0; i < plugin.settings.preloaded.length; i++) {
                        $uploadedContainer.append(createImg(plugin.settings.preloaded[i].src, plugin.settings.preloaded[i].id, !0));
                    }
                }
            });
        };
        let dataTransfer = new DataTransfer();
        let createContainer = function () {
            let $container = $("<div>", { class: "image-uploader" }),
                $input = $("<input>", { type: "file", id: plugin.settings.imagesInputName, name: plugin.settings.imagesInputName + "[]", multiple: "" }).appendTo($container),
                $uploadedContainer = $("<div>", { class: "uploaded" }).appendTo($container),
                $textContainer = $("<div>", { class: "upload-text" }).appendTo($container),
                $i = $("<i>", { class: "material-icons", text: "cloud_upload" }).appendTo($textContainer),
                $span = $("<span>", { text: plugin.settings.label }).appendTo($textContainer);
            $container.on("click", function (e) {
                prevent(e);
                $input.trigger("click");
            });
            $input.on("click", function (e) {
                e.stopPropagation();
            });
            $input.on("change", fileSelectHandler.bind($container));
            return $container;
        };
        let prevent = function (e) {
            e.preventDefault();
            e.stopPropagation();
        };
        let createImg = function (src, id) {
            $img_index = $('.img_index').val();
            let $container = $("<div>", { class: "uploaded-image" }),
                $img = $("<img>", { src: src }).appendTo($container),
                $button = $("<button>", { class: "delete-image" }).appendTo($container),
               
                $i = $("<i>", { class: "fa fa-times", text: "" }).appendTo($button);
            if (plugin.settings.preloaded.length) {
                $container.attr("data-preloaded", !0);
                let $preloaded = $("<input>", { type: "hidden", name: plugin.settings.preloadedInputName + "[]", value: id }).appendTo($container);
            } else {
                $container.attr("data-index", id);
                if ($img_index != "") {
                    $image_index = $img_index + ',' + id;
                } else {
                    $image_index = id;
                }
                $(".img_index").val($image_index);
            }
            $container.on("click", function (e) {
                prevent(e);
            });
            $button.on("click", function (e) {
                prevent(e);
                if ($container.data("index")) {
                    let index = parseInt($container.data("index"));
                    $container.find(".uploaded-image[data-index]").each(function (i, cont) {
                        if (i > index) {
                            $(cont).attr("data-index", i - 1);
                        }
                    });
                    dataTransfer.items.remove(index);
                }
                $container.remove();
                if (!$container.find(".uploaded-image").length) {
                    let index = parseInt($container.data("index"));
                    let allimg_index = JSON.parse("[" + $('.img_index').val() + "]");
                    $removed_img_index = allimg_index.splice(index, 1);
                    $('.img_index').val(allimg_index);
                    $container.removeClass("has-files");
                }
            });
             // Add a specific class only to the first image with data-index="0"
   
            
                        return $container;
        };
        let fileDragHover = function (e) {
            prevent(e);
            if (e.type === "dragover") {
                $(this).addClass("drag-over");
            } else {
                $(this).removeClass("drag-over");
            }
        };
        let fileSelectHandler = function (e) {
            prevent(e);
            let $container = $(this);
            $container.removeClass("drag-over");
            let files = e.target.files || e.originalEvent.dataTransfer.files;
            setPreview($container, files);
        };

        let deleteImageHandler = function ($container) {
            prevent(e);
            if ($container.data("index")) {
                let index = parseInt($container.data("index"));
                $container.find(".uploaded-image[data-index]").each(function (i, cont) {
                    if (i > index) {
                        $(cont).attr("data-index", i - 1);
                    }
                });
                dataTransfer.items.remove(index);
            }
            $container.remove();
            if (!$container.find(".uploaded-image").length) {
                let index = parseInt($container.data("index"));
                let allimg_index = JSON.parse("[" + $('.img_index').val() + "]");
                $removed_img_index = allimg_index.splice(index, 1);
                $('.img_index').val(allimg_index);
                $container.removeClass("has-files");
            }
        };
        let setPreview = function ($container, files) {
            $container.addClass("has-files");
            let $uploadedContainer = $container.find(".uploaded"),
                $input = $container.find('input[type="file"]');
        
            $(files).each(function (i, file) {
                var upload_img_count = $('.upload_img_count').val();
                var max_img_upload_count = $('.max_img_upload_count').val();
                var upload_page = $('.upload_page').val();
        
                if (upload_page == "Add") {
                    var adding_img_count = max_img_upload_count;
                } else if (upload_page == "Edit") {
                    var adding_img_count = max_img_upload_count - upload_img_count;
                }
        
              
                if (dataTransfer.items.length < adding_img_count) {
                    var get_img_type = file.type.split('/').pop().toLowerCase();
                    if (get_img_type != "jpeg" && get_img_type != "jpg" && get_img_type != "png" && get_img_type != "webp") {
                        toastr.warning('Allowed only image files');
                    } else {
                        dataTransfer.items.add(file);
                        $uploadedContainer.append(createImg(URL.createObjectURL(file), dataTransfer.items.length - 1));
                    }
                } else {
                    toastr.warning('Limit reached. Allowed ' + max_img_upload_count + ' images only!');
                }
            });
        
            $input.prop("files", dataTransfer.files);
        
            // Move the clicked image to the first position in the preview
                            
            $(document).on("mousedown", ".uploaded-image", function () {
                console.log('debug');
            
                // Remove the 'first-image-container' class from all elements
                $uploadedContainer.find(".uploaded-image").removeClass('first-image-container');
            
                // Add the class only to the most recently clicked image
                let $clickedImage = $(this).prependTo($uploadedContainer).addClass('first-image-container');
            
                // Remove existing 'Default' tags from other images
                $uploadedContainer.find(".uploaded-image").not($clickedImage).find(".default-tag").remove();
            
                // Add <p> tag with class 'default-tag' to the clicked image
                $("<p>", { class: "default-tag text-base sm:text-md md:text-lg lg:text-xl text-gray-500 font-semibold leading-relaxed", text: "Default" }).insertBefore($clickedImage.find(".delete-image"));
            
                // Update data-index values for all .uploaded-image elements based on their order
                $uploadedContainer.find(".uploaded-image").each(function (index) {
                    $(this).attr("data-index", index);
                });
            });
            

                        // Bind the deleteImageHandler to the delete-image button
                 $(document).on("mousedown", ".delete-image", function (e) {
                    console.log('dek')
                    let $imageContainer = $(this).closest(".uploaded-image");
                    deleteImageHandler($imageContainer);
                });
        };
        
        let random = function () {
            return Date.now() + Math.floor(Math.random() * 100 + 1);
        };
        this.init();
        return this;
    };
})(jQuery);